INSERT INTO [dbo].[ExamplePrompts] ([Title], [Prompt], [Description], [ServiceCode], [Model], [Category], [IconClass], [SortOrder], [IsActive])
VALUES
    (N'추상 표현주의 회화', N'추상 표현주의 스타일의 회화 작품, 대담한 붓질, 감정적 표현, 자유로운 형태, 생동감 있는 색상, 현대 미술, 갤러리 품질, 예술적 자유', N'추상 표현주의 스타일의 현대 회화 작품을 생성합니다. 대담하고 감정적인 표현이 특징입니다.', N'gemini-image', NULL, N'회화', N'bi bi-paint-bucket', 21, 1),
    (N'자연 사진 콜라주', N'자연 사진 콜라주, 다양한 자연 요소 결합, 창의적인 합성, 아름다운 색상 조화, 전문 사진 편집, 예술적 구성, 자연의 아름다움 강조', N'자연 사진들을 창의적으로 합성한 콜라주 작품을 생성합니다. 다양한 자연 요소가 조화롭게 어우러집니다.', N'gemini-image', NULL, N'콜라주', N'bi bi-images', 22, 1),
    (N'미니멀 로고 디자인', N'미니멀 로고 디자인, 깔끔한 선, 단순한 형태, 현대적인 브랜딩, 세련된 타이포그래피, 기억에 남는 디자인, 전문 로고 아트, 고급스러운 느낌', N'미니멀하고 세련된 로고 디자인을 생성합니다. 깔끔하고 기억에 남는 브랜드 아이덴티티를 표현합니다.', N'gemini-image', NULL, N'로고', N'bi bi-badge', 23, 1),
    (N'수채화 풍경', N'수채화 스타일의 풍경 그림, 부드러운 색감, 물감이 번지는 효과, 자연스러운 색상 전환, 예술적 수채화 기법, 아름다운 풍경, 전문 수채화 아트', N'수채화 기법으로 그려진 아름다운 풍경 그림을 생성합니다. 부드럽고 자연스러운 색감이 특징입니다.', N'gemini-image', NULL, N'수채화', N'bi bi-palette2', 24, 1),
    (N'3D 렌더링 아트', N'3D 렌더링 아트, 사실적인 재질, 전문 3D 그래픽, 현대적인 3D 디자인, 고품질 렌더링, 세밀한 디테일, 3D 시각화, 전문 3D 아트', N'고품질 3D 렌더링 작품을 생성합니다. 사실적인 재질과 세밀한 디테일이 특징입니다.', N'gemini-image', NULL, N'3D', N'bi bi-box', 25, 1),
    (N'벡터 일러스트', N'벡터 일러스트, 깔끔한 선, 선명한 색상, 확대 가능한 그래픽, 현대적인 일러스트 스타일, 전문 벡터 아트, 상업용 일러스트, 고품질 벡터 그래픽', N'깔끔하고 선명한 벡터 일러스트를 생성합니다. 확대해도 선명한 고품질 그래픽입니다.', N'gemini-image', NULL, N'벡터', N'bi bi-diagram-3', 26, 1),
    (N'야경 사진', N'아름다운 야경 사진, 도시 불빛, 별이 보이는 하늘, 일몰 또는 일출, 자연 야경, 전문 야경 사진, 드라마틱한 조명, 평화로운 밤 풍경', N'아름다운 야경을 포착한 전문 사진을 생성합니다. 도시 불빛과 별이 어우러진 밤 풍경입니다.', N'gemini-image', NULL, N'야경', N'bi bi-moon-stars', 27, 1),
    (N'팝아트 스타일', N'팝아트 스타일의 일러스트, 대담한 색상, 강렬한 대비, 현대적인 팝아트, 유명인 또는 아이콘, 그래픽 디자인, 세련된 팝아트 아트, 고급 팝아트 스타일', N'대담하고 강렬한 팝아트 스타일의 일러스트를 생성합니다. 생동감 있는 색상과 강한 대비가 특징입니다.', N'gemini-image', NULL, N'팝아트', N'bi bi-star-fill', 28, 1),
    (N'건축 스케치', N'건축 스케치, 손그림 느낌, 건축 도면 스타일, 전문 건축 일러스트, 상세한 건축 디테일, 현대 건축 스케치, 건축 설계도, 아티스틱한 건축 그림', N'손그림 스타일의 전문 건축 스케치를 생성합니다. 상세한 건축 디테일과 아티스틱한 느낌이 특징입니다.', N'gemini-image', NULL, N'건축', N'bi bi-pencil', 29, 1),
    (N'판타지 캐릭터', N'판타지 캐릭터 디자인, 마법사 또는 전사, 판타지 세계관, 상세한 캐릭터 아트, 전문 판타지 일러스트, 애니메이션 스타일, 매력적인 캐릭터, 판타지 RPG 느낌', N'판타지 세계관의 상세한 캐릭터 디자인을 생성합니다. 마법사나 전사 등 다양한 판타지 캐릭터를 표현합니다.', N'gemini-image', NULL, N'판타지', N'bi bi-sword', 30, 1);
